SELECT count(*) FROM hm_query.cms_pages_flat

    AND slug LIKE CONCAT('%', #{slug}, '%')
    AND title LIKE CONCAT('%', #{title}, '%')
    AND page_type = #{pageType}
    AND published = #{published}
    AND published_at >= #{startDate}
    AND published_at <= #{endDate}
    AND (title LIKE CONCAT('%', #{q}, '%') OR slug LIKE CONCAT('%', #{q}, '%'))

SELECT
    id                 as "id",
    slug               as "slug",
    title              as "title",
    page_type          as "pageType",
    published          as "published",
    published_at       as "publishedAt"
FROM hm_query.cms_pages_flat

    AND slug LIKE CONCAT('%', #{slug}, '%')
    AND title LIKE CONCAT('%', #{title}, '%')
    AND page_type = #{pageType}
    AND published = #{published}
    AND published_at >= #{startDate}
    AND published_at <= #{endDate}
    AND (title LIKE CONCAT('%', #{q}, '%') OR slug LIKE CONCAT('%', #{q}, '%'))

${orderby} ${pagination}

