SELECT count(*) FROM hm_query.cms_media_flat

    AND original_name LIKE CONCAT('%', #{originalName}, '%')
    AND mime_type = #{mimeType}
    AND folder = #{folder}
    AND (original_name LIKE CONCAT('%', #{q}, '%') OR alt_text LIKE CONCAT('%', #{q}, '%'))

SELECT id as "id", file_key as "fileKey", original_name as "originalName", cdn_url as "cdnUrl", mime_type as "mimeType", file_size_bytes as "fileSizeBytes", width as "width", height as "height", alt_text as "altText", folder as "folder" FROM hm_query.cms_media_flat
AND original_name LIKE CONCAT('%', #{originalName}, '%') AND mime_type = #{mimeType} AND folder = #{folder} AND (original_name LIKE CONCAT('%', #{q}, '%') OR alt_text LIKE CONCAT('%', #{q}, '%'))
${orderby} ${pagination}

